#include<bits/stdc++.h>
#define now [flag][cnt][ax][ay][bx][by]
using namespace std;
int n,r1,c1,r2,c2;
int f[2][71][21][21][21][21];
int dx[4]={1,0,-1,0};
int dy[4]={0,1,0,-1};
int dfs(bool flag,int cnt,int ax,int ay,int bx,int by)
{
    if(f now!=-1)
    {
        return f now;
    }
    if(cnt>n*3)
    {
        return f now=1e9;
    }
    if(ax==bx&&ay==by)
    {
        return f now=(flag?0:1e9);
    }
    int ans;
    if(flag)
    {
        ans=-1;
        for(int i=0;i<4;i++)
        {
            int xx=ax+dx[i],yy=ay+dy[i];
            if(xx<1||xx>n||yy<1||yy>n)
            {
                continue;
            }
            ans=max(ans,dfs(0,cnt+1,xx,yy,bx,by));
        }
    }
    else
    {
        ans=1e9;
        for(int i=0;i<4;i++)
        {
            for(int j=1;j<=2;j++)
            {
                int xx=bx+dx[i]*j,yy=by+dy[i]*j;
                if(xx<1||xx>n||yy<1||yy>n)
                {
                    continue;
                }
                ans=min(ans,dfs(1,cnt+1,ax,ay,xx,yy));
            }
        }
    }
    return f now=ans+1;
}
int main()
{
    memset(f,-1,sizeof(f));
    scanf("%d%d%d%d%d",&n,&r1,&c1,&r2,&c2);
    if(abs(r1-r2)+abs(c1-c2)==1)
    {
        printf("WHITE 1");
        return 0;
    }
    printf("BLACK %d",dfs(1,0,r1,c1,r2,c2));
    return 0;
}
